public void dialog()
{
    Dialog                       dialog;
    TransDate                    fromDate,toDate;
    DialogField                  dialogFromDate,dialogToDate;
    dialog = new dialog("Vendor open transactions");
    dialogFromDate       = dialog.addField(extendedTypeStr(TransDate), "As of date");
   // dialogToDate         = dialog.addField(extendedTypeStr(TransDate), "To date");
    dialog.run();
    if(dialogFromDate.value() >= today())
    {
        throw error("As of date should not be greater than Today's Date'");
    }
    else if (dialog.run())
    {
        this.createVendOpenTransData(dialogFromDate.value());
    }
}

/// <summary>
///
/// </summary>
/// <param name = "_fromdate"></param>
/// <param name = "_todate"></param>
public void createVendOpenTransData(date _fromdate)
{
    ETGVendOpenTrans vendOpenTrans;
    VendTrans vendTrans;
    VendTable vendTable;
    date fromdate, todate;
    timeofday fromtime, totime;

    str businessUnitValue, profitCenterValue, projectValue, product_ServiceValue,verticalValue,
        MAIN_COMMODITYValue, SUB_COMMODITYValue, lineOfBusinessValue, contractValue, plantWarehouseOfficeValue,
        departmentValue, interCompanyValue, trader_EmployeeValue, itemValue;;
    str businessUnitStr = "BusinessUnit";
    str profitCenterStr = "ProfitCenter";
    str projectStr = "Project";
    str product_ServiceStr = "Product_Service";
    str verticalStr = "Vertical";
    str MAIN_COMMODITYStr = "MainCommodity";
    str SUB_COMMODITYStr = "SubCommodity";
    str lineOfBusinessStr = "Line_of_Business";
    str contractsStr = "Contract";
    str plantWarehouseOfficeStr = "Plant_Warehouse_Office";
    str departmentStr = "Department";
    str interCompanyStr = "InterCompany";
    str trader_EmployeeStr = "Trader_Employee";
    str itemStr = "Item";

    Args args = new Args();
    ;
    ttsbegin;
    delete_from vendOpenTrans;
    ttscommit;

    while select vendTrans
        where vendTrans.DataAreaId == curext()
        && vendTrans.TransDate <= _fromdate
        && (vendTrans.Closed == dateNull()
        || vendTrans.Closed <= _fromdate)
    if(vendTrans)
    {
        vendOpenTrans.PostingProfile = vendTrans.PostingProfile;
        vendOpenTrans.AccountingEvent = vendTrans.AccountingEvent;
        vendOpenTrans.AccountNum = vendTrans.AccountNum;
        vendOpenTrans.AmountCur = vendTrans.AmountCur;
        vendOpenTrans.AmountMST = vendTrans.AmountMST;
        vendOpenTrans.Approved = vendTrans.Approved;
        vendOpenTrans.ApprovedDate = vendTrans.ApprovedDate;
        vendOpenTrans.Approver = vendTrans.Approver;
        vendOpenTrans.Arrival = vendTrans.Arrival;
        vendOpenTrans.BankCentralBankPurposeCode = vendTrans.BankCentralBankPurposeCode;
        vendOpenTrans.BankCentralBankPurposeText = vendTrans.BankCentralBankPurposeText;
        vendOpenTrans.BankLCImportLine = vendTrans.BankLCImportLine;
        vendOpenTrans.BankRemittanceFileId = vendTrans.BankRemittanceFileId;
        vendOpenTrans.Cancel = vendTrans.Cancel;
        vendOpenTrans.CashDiscBaseDate = vendtrans.CashDiscBaseDate;
        vendOpenTrans.CashDiscCode = vendTrans.CashDiscCode;
        vendOpenTrans.Closed = vendTrans.Closed;
        vendOpenTrans.CompanyBankAccountId = vendTrans.CompanyBankAccountId;
        vendOpenTrans.Correct = vendTrans.Correct;
        vendOpenTrans.CurrencyCode = vendTrans.CurrencyCode;
        vendOpenTrans.DefaultDimension = vendTrans.DefaultDimension;
        vendOpenTrans.DocumentDate = vendTrans.DocumentDate;
        vendOpenTrans.DocumentNum = vendTrans.DocumentNum;
        vendOpenTrans.DueDate = vendTrans.DueDate;
        vendOpenTrans.EUROTriangulation = vendTrans.EUROTriangulation;
        vendOpenTrans.ExchAdjustment = vendTrans.ExchAdjustment;
        vendOpenTrans.ExchAdjustmentReporting = vendTrans.ExchAdjustmentReporting;
        vendOpenTrans.ExchRate = vendOpenTrans.ExchRate;
        vendOpenTrans.ExchRateSecond = vendTrans.ExchRateSecond;
        vendOpenTrans.FixedExchRate = vendTrans.FixedExchRate;
        vendOpenTrans.Invoice = vendTrans.Invoice;
        vendOpenTrans.InvoiceProject = vendTrans.InvoiceProject;
        vendOpenTrans.InvoiceReleaseDate = vendTrans.InvoiceReleaseDate;
        vendOpenTrans.JournalNum = vendTrans.JournalNum;
        vendOpenTrans.LastExchAdj = vendTrans.LastExchAdj;
        vendOpenTrans.LastExchAdjRate = vendTrans.LastExchAdjRate;
        vendOpenTrans.LastExchAdjRateReporting = vendTrans.LastExchAdjRateReporting;
        vendOpenTrans.LastExchAdjVoucher = vendTrans.LastExchAdjVoucher;
        vendOpenTrans.LastSettleAccountNum = vendTrans.LastSettleAccountNum;
        vendOpenTrans.LastSettleCompany = vendTrans.LastSettleCompany;
        vendOpenTrans.LastSettleDate = vendTrans.LastSettleDate;
        vendOpenTrans.LastSettleVoucher = vendTrans.LastSettleVoucher;
        vendOpenTrans.OffsetRecid = vendTrans.OffsetRecid;
        vendOpenTrans.PackedExtensions = vendTrans.PackedExtensions;
        vendOpenTrans.PaymId = vendTrans.PaymId;
        vendOpenTrans.PaymMode = vendTrans.PaymMode;
        vendOpenTrans.PaymReference = vendTrans.PaymReference;
        vendOpenTrans.PaymSpec = vendTrans.PaymSpec;
        vendOpenTrans.PaymTermId = vendTrans.PaymTermId;
        vendOpenTrans.PostingChangeVoucher = vendTrans.PostingChangeVoucher;
        vendOpenTrans.PostingProfileApprove = vendTrans.PostingProfileApprove;
        vendOpenTrans.PostingProfileCancel = vendTrans.PostingProfileCancel;
        vendOpenTrans.PostingProfileClose = vendTrans.PostingProfileClose;
        vendOpenTrans.PostingProfileReOpen = vendTrans.PostingProfileReOpen;
        vendOpenTrans.Prepayment = vendTrans.Prepayment;
        vendOpenTrans.PromissoryNoteID = vendTrans.PromissoryNoteID;
        vendOpenTrans.PromissoryNoteSeqNum = vendTrans.PromissoryNoteSeqNum;
        vendOpenTrans.PromissoryNoteStatus = vendTrans.PromissoryNoteStatus;
        vendOpenTrans.RBOVendTrans = vendTrans.RBOVendTrans;
        vendOpenTrans.ReasonRefRecId = vendTrans.ReasonRefRecId;
        vendOpenTrans.ReleaseDateComment = vendTrans.ReleaseDateComment;
        vendOpenTrans.RemittanceAddress = vendTrans.RemittanceAddress;
        vendOpenTrans.RemittanceLocation = vendTrans.RemittanceLocation;
        vendOpenTrans.ReportingCurrencyAmount = vendTrans.ReportingCurrencyAmount;
        vendOpenTrans.ReportingCurrencyCrossRate = vendTrans.ReportingCurrencyCrossRate;
        vendOpenTrans.ReportingExchAdjustmentRealized = vendTrans.ReportingExchAdjustmentRealized;
        vendOpenTrans.ReportingExchAdjustmentUnrealized = vendTrans.ReportingExchAdjustmentUnrealized;
        vendOpenTrans.SettleAmountCur = vendTrans.SettleAmountCur;
        vendOpenTrans.SettleAmountMST = vendTrans.SettleAmountMST;
        vendOpenTrans.SettleAmountReporting = vendTrans.SettleAmountReporting;
        vendOpenTrans.Settlement = vendTrans.Settlement;
        vendOpenTrans.SettleTax1099Amount = vendTrans.SettleTax1099Amount;
        vendOpenTrans.SettleTax1099StateAmount = vendTrans.SettleTax1099StateAmount;
        vendOpenTrans.Tax1099Amount = vendTrans.Tax1099Amount;
        vendOpenTrans.Tax1099Date = vendTrans.Tax1099Date;
        vendOpenTrans.Tax1099Fields = vendTrans.Tax1099Fields;
        vendOpenTrans.Tax1099Num = vendTrans.Tax1099Num;
        vendOpenTrans.Tax1099RecId = vendTrans.Tax1099RecId;
        vendOpenTrans.Tax1099State = vendTrans.Tax1099State;
        vendOpenTrans.Tax1099StateAmount = vendTrans.Tax1099StateAmount;
        vendOpenTrans.TaxInvoicePurchId = vendTrans.TaxInvoicePurchId;
        vendOpenTrans.ThirdPartyBankAccountId = vendTrans.ThirdPartyBankAccountId;
        vendOpenTrans.TransDate = vendTrans.TransDate;
        vendOpenTrans.TransType = vendTrans.TransType;
        vendOpenTrans.Txt = vendTrans.Txt;
        vendOpenTrans.VendExchAdjustmentRealized = vendTrans.VendExchAdjustmentRealized;
        vendOpenTrans.VendExchAdjustmentUnrealized = vendTrans.VendExchAdjustmentUnrealized;
        vendOpenTrans.VendPaymentGroup = vendTrans.VendPaymentGroup;
        vendOpenTrans.Voucher = vendTrans.Voucher;
        vendOpenTrans.ReportingCurrencyExchRate = vendTrans.ReportingCurrencyExchRate;
        vendOpenTrans.ReportingCurrencyExchRateSecondary = vendTrans.ReportingCurrencyExchRateSecondary;
        vendOpenTrans.ArrivalAccountId = vendTrans.ArrivalAccountId;
        vendOpenTrans.SummaryAccountId = vendTrans.SummaryAccountId;
        vendOpenTrans.VendorName = vendTrans.vendTableName();


        select * from vendTable where vendTable.AccountNum == vendTrans.AccountNum;

        vendOpenTrans.VendGroup = vendTable.VendGroup;

        businessUnitValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, businessUnitStr);

        if(businessUnitValue)
        {
            vendOpenTrans.BusinessUnit = businessUnitValue;
        }
        profitCenterValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, profitCenterStr);

        if(profitCenterValue)
        {
            vendOpenTrans.ProfitCenter = profitCenterValue;
        }
        projectValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, projectStr);

        if(projectValue)
        {
            vendOpenTrans.Project = projectValue;
        }
        product_ServiceValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, product_ServiceStr);

        if(product_ServiceValue)
        {
            vendOpenTrans.Product_Service = product_ServiceValue;
        }

        verticalValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, verticalStr);

        if(verticalValue)
        {
            vendOpenTrans.Vertical = verticalValue;
        }

        MAIN_COMMODITYValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, MAIN_COMMODITYStr);

        if(MAIN_COMMODITYValue)
        {
            vendOpenTrans.MainCommodity = MAIN_COMMODITYValue;
        }

        SUB_COMMODITYValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, SUB_COMMODITYStr);

        if(SUB_COMMODITYValue)
        {
            vendOpenTrans.SubCommodity = SUB_COMMODITYValue;
        }

        lineOfBusinessValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, lineOfBusinessStr);

        if(lineOfBusinessValue)
        {
            vendOpenTrans.LineOfBusiness = lineOfBusinessValue;
        }

        contractValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, contractsStr);

        if(contractValue)
        {
            vendOpenTrans.Contract = contractValue;
        }

        plantWarehouseOfficeValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, plantWarehouseOfficeStr);

        if(plantWarehouseOfficeValue)
        {
            vendOpenTrans.PlantWarehouseOffice = plantWarehouseOfficeValue;
        }

        departmentValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, departmentStr);

        if(departmentValue)
        {
            vendOpenTrans.Department = departmentValue;
        }

        interCompanyValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, interCompanyStr);

        if(interCompanyValue)
        {
            vendOpenTrans.InterCompany = interCompanyValue;
        }

        trader_EmployeeValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, trader_EmployeeStr);

        if(trader_EmployeeValue)
        {
            vendOpenTrans.TraderEmployee = trader_EmployeeValue;
        }

        itemValue = ETGBankTransFinDim::getDimensionDisplayValue(vendTrans.DefaultDimension, itemStr);

        if(itemValue)
        {
            vendOpenTrans.Item = itemValue;
        }
        vendOpenTrans.ETGBalanceTC = vendTrans.AmountCur - vendTrans.SettleAmountCur;

        if(vendTrans.LastExchAdjRate)
        {
            vendOpenTrans.ETGNewExchRate = vendTrans.LastExchAdjRate;
            vendOpenTrans.ETGBalanceUSD = vendOpenTrans.ETGBalanceTC * vendTrans.LastExchAdjRate;
        }            
        else if(vendTrans.ExchRate != 0.00)
        {                
            vendOpenTrans.ETGNewExchRate = vendTrans.ExchRate/100;
            vendOpenTrans.ETGBalanceUSD = vendOpenTrans.ETGBalanceTC * vendOpenTrans.ETGNewExchRate;
        }
        else if(vendTrans.ExchRate == 0.00)
        {
            vendOpenTrans.ETGNewExchRate = 0.00;
            vendOpenTrans.ETGBalanceUSD = vendOpenTrans.ETGBalanceTC * vendOpenTrans.ETGNewExchRate;
        }

        vendOpenTrans.insert();
    }
    new MenuFunction(menuItemdisplayStr(ETGVendTransOpen),MenuItemType::Display).run();
}

/// <summary>
///
/// </summary>
/// <param name = "_args"></param>
public static void main(Args _args)
{
    ETGVendorOpenTrans vendorOpenTrans;
    vendorOpenTrans = new ETGVendorOpenTrans();
    vendorOpenTrans.run();
}
